    const dimCmds = {
      DISTANCE: `DIM/${feat1}_TO_${feat2}= DISTANCE FROM ${feat1} TO ${feat2},$\n    NOMINAL=${nominal},TOL_U=${upper},TOL_L=${lower}$\n    `,
      POSITION: `DIM/${feat1}_POS= POSITION OF ${feat1},$\n    NOMINAL=${nominal},TOL_U=${upper},TOL_L=${lower}$\n    `,
      TRUE_POSITION: `DIM/${feat1}_TP= TRUE POSITION OF ${feat1},$\n    NOMINAL=${nominal},TOL_U=${upper},TOL_L=${lower}$\n    `,
      FLATNESS: `DIM/${feat1}_FLAT= FLATNESS OF ${feat1},$\n    NOMINAL=${nominal},TOL_U=${upper}$\n    `,
      ROUNDNESS: `DIM/${feat1}_ROUND= ROUNDNESS OF ${feat1},$\n    NOMINAL=${nominal},TOL_U=${upper}$\n    `,
      ANGLE: `DIM/${feat1}_TO_${feat2}= ANGLE BETWEEN ${feat1} AND ${feat2},$\n    NOMINAL=${nominal},TOL_U=${upper},TOL_L=${lower}$\n    `,
    };

    const cmd = dimCmds[dimType.toUpperCase()];
    if (!cmd) return `不支持的尺寸类型: ${dimType}`;

    return this.addCommand(cmd);
  }

  createAlignment(name, levelFeature, rotateFeature, originFeature) {
    if (!this.connected) return '错误：未连接到 PC-DMIS';
    const parts = [`ALIGNMENT/START,${name}`];
    if (levelFeature) parts.push(`${name}_${levelFeature}_LEVEL= ALIGN/LEVEL,ZPLUS,${levelFeature}`);
    if (rotateFeature) parts.push(`${name}_${rotateFeature}_ROTATE= ALIGN/ROTATE,XPLUS,TO,${rotateFeature},ABOUT,ZPLUS`);
    if (originFeature) parts.push(`${name}_ORIGIN= ALIGN/TRANS,XAXIS,${originFeature},YAXIS,${originFeature},ZAXIS,${originFeature}`);
    parts.push('ALIGNMENT/END');

    const results = parts.map(p => this.addCommand(p));
    return `已创建对齐 '${name}':\n${parts.join('\n')}`;
  }
}

